    else:
        strongest = np.argsort(P_music)[-num_sources:]
    strongest = np.sort(strongest)
    theta_hat = _sort_theta(theta_grid_rad[strongest])

    return theta_hat, P_music, strongest, dominant_two_exists, E_n, eigvals


